var idSuffixes = []string{
	"_identifier", "_reference", "_number", "_num",
	"_code", "_key", "_id", "_ref", "_no",
}

// stripIDAlias returns the suffix-stripped alias for an entity ID and true,
// or empty string and false if no suffix matches.
func stripIDAlias(entityID string) (string, bool) {
	for _, suffix := range idSuffixes {
		if strings.HasSuffix(entityID, suffix) && len(entityID) > len(suffix) {
			return entityID[:len(entityID)-len(suffix)], true
		}
	}
	return "", false
}

// nerConfigFingerprint builds a sorted JSON payload and returns its MD5 hex digest.
func nerConfigFingerprint(spacyModel string, useSchemaVocab bool, vocabEntities []map[string]interface{}) (string, error) {
	entityStrs := make([]string, 0, len(vocabEntities))
	for _, e := range vocabEntities {
		b, err := json.Marshal(e)
		if err != nil {
			return "", fmt.Errorf("marshal vocab entity: %w", err)
		}
		entityStrs = append(entityStrs, string(b))
	}
	sort.Strings(entityStrs)
	payload := map[string]interface{}{
		"spacy_model":      spacyModel,
		"use_schema_vocab": useSchemaVocab,
		"vocab_entities":   entityStrs,
	}
	b, err := json.Marshal(payload)
	if err != nil {
		return "", fmt.Errorf("marshal fingerprint payload: %w", err)
	}
	sum := md5.Sum(b)
	return hex.EncodeToString(sum[:]), nil
}

