// buildVocabMatchers builds schema and data matchers when vocabulary sources are configured.
// Returns (schemaMatcher, dataMatcher) — either may be nil.
func buildVocabMatchers(allChunks []Chunk, useSchemaVocab bool, vocabEntities []map[string]interface{}) (Matcher, Matcher, error) {
	if !useSchemaVocab && len(vocabEntities) == 0 {
		return nil, nil, nil
	}
	builder := NewSchemaVocabBuilder()
	if useSchemaVocab {
		builder.AddChunks(allChunks)
	}
	for _, entry := range vocabEntities {
		etype := "term"
		if v, ok := entry["entity_type"].(string); ok && v != "" {
			etype = v
		}
		entryType, _ := entry["type"].(string)
		if entryType == "static" {
			names, _ := entry["names"].([]string)
			builder.AddEntities(names, etype)
		} else if entryType == "db_query" {
			conn, _ := entry["connection"].(string)
			sql, _ := entry["sql"].(string)
			if err := builder.AddFromDB(conn, map[string]string{etype: sql}); err != nil {
				return nil, nil, fmt.Errorf("add_from_db: %w", err)
			}
		}
	}
	schemaMatcher, err := builder.Build()
	if err != nil {
		return nil, nil, fmt.Errorf("build schema matcher: %w", err)
	}
	var dataMatcher Matcher
	if builder.DataTermCount() > 0 {
		dataMatcher, err = builder.BuildDataMatcher()
		if err != nil {
			return nil, nil, fmt.Errorf("build data matcher: %w", err)
		}
	}
	return schemaMatcher, dataMatcher, nil
}

