// checkCache determines incremental mode and skip set.
// Returns (shouldReturnEarly, incremental, skipIDs).
// shouldReturnEarly=true means caller should return the current chunk_entities count.
func checkCache(con *sql.DB, fingerprint string, force bool) (bool, bool, map[string]struct{}, error) {
	allRows, err := con.Query("SELECT chunk_id FROM embeddings")
	if err != nil {
		return false, false, nil, fmt.Errorf("query embeddings: %w", err)
	}
	defer allRows.Close()
	allChunkIDs := make(map[string]struct{})
	for allRows.Next() {
		var id string
		if err := allRows.Scan(&id); err != nil {
			return false, false, nil, fmt.Errorf("scan chunk_id: %w", err)
		}
		allChunkIDs[id] = struct{}{}
	}
	procRows, err := con.Query("SELECT DISTINCT chunk_id FROM chunk_entities")
	if err != nil {
		return false, false, nil, fmt.Errorf("query chunk_entities: %w", err)
	}
	defer procRows.Close()
	processedIDs := make(map[string]struct{})
	for procRows.Next() {
		var id string
		if err := procRows.Scan(&id); err != nil {
			return false, false, nil, fmt.Errorf("scan processed_id: %w", err)
		}
		processedIDs[id] = struct{}{}
	}
	var cachedCount *int
	row := con.QueryRow("SELECT chunk_count FROM ner_cache WHERE config_fingerprint = ?", fingerprint)
	var cnt int
	if err := row.Scan(&cnt); err == nil {
		cachedCount = &cnt
	}
	configMatch := cachedCount != nil
	newChunkIDs := make(map[string]struct{})
	for id := range allChunkIDs {
		if _, found := processedIDs[id]; !found {
			newChunkIDs[id] = struct{}{}
		}
	}
	if force {
		return false, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) == 0 {
		return true, false, make(map[string]struct{}), nil
	}
	if configMatch && len(newChunkIDs) > 0 {
		return false, true, processedIDs, nil
	}
	return false, false, make(map[string]struct{}), nil
}

