// persistAssociations writes associations and entities to the DB, clearing first unless incremental.
func persistAssociations(con *sql.DB, associations []map[string]interface{}, entityMeta map[string][3]string, incremental bool) error {
	if !incremental {
		if _, err := con.Exec("DELETE FROM chunk_entities"); err != nil {
			return fmt.Errorf("delete chunk_entities: %w", err)
		}
		if _, err := con.Exec("DELETE FROM entities"); err != nil {
			return fmt.Errorf("delete entities: %w", err)
		}
	}
	for _, a := range associations {
		chunkID, _ := a["chunk_id"].(string)
		entityID, _ := a["entity_id"].(string)
		frequency, _ := a["frequency"].(int)
		positions, _ := a["positions"].([]int)
		score, _ := a["score"].(float64)
		posJSON, err := json.Marshal(positions)
		if err != nil {
			return fmt.Errorf("marshal positions: %w", err)
		}
		var chunkNamespace *string
		row := con.QueryRow("SELECT namespace FROM embeddings WHERE chunk_id = ?", chunkID)
		var ns string
		if scanErr := row.Scan(&ns); scanErr == nil {
			chunkNamespace = &ns
		}
		_, err = con.Exec(
			"INSERT OR REPLACE INTO chunk_entities(chunk_id, entity_id, frequency, positions_json, score, namespace) VALUES (?,?,?,?,?,?)",
			chunkID, entityID, frequency, string(posJSON), score, chunkNamespace,
		)
		if err != nil {
			return fmt.Errorf("insert chunk_entities: %w", err)
		}
		name, displayName, entityType := entityID, entityID, "concept"
		if meta, ok := entityMeta[entityID]; ok {
			name, displayName, entityType = meta[0], meta[1], meta[2]
		}
		_, err = con.Exec(
			"INSERT OR IGNORE INTO entities(id, name, display_name, entity_type) VALUES (?,?,?,?)",
			entityID, name, displayName, entityType,
		)
		if err != nil {
			return fmt.Errorf("insert entity: %w", err)
		}
		if alias, ok := stripIDAlias(entityID); ok {
			_, err = con.Exec(
				"INSERT OR IGNORE INTO entity_aliases(alias, entity_id, source) VALUES (?,?,?)",
				alias, entityID, "strip_suffix",
			)
			if err != nil {
				return fmt.Errorf("insert entity_alias: %w", err)
			}
		}
	}
	return nil
}

// BuildNEROptions holds optional parameters for BuildNER.
type BuildNEROptions struct {
	SpacyModel        string
	UseSchemaVocab    bool
	VocabEntities     []map[string]interface{}
	Force             bool
	BuildContextGraph bool
	Namespace         string
}

// BuildNER runs NER on all chunks in store and persists results to chunk_entities.
// Returns the number of chunk_entities associations written.
func BuildNER(store *Store, opts BuildNEROptions) (int, error) {
	if opts.SpacyModel == "" {
		opts.SpacyModel = DefaultSpacyModel
	}
	if opts.Namespace == "" {
		opts.Namespace = "global"
	}
	con := store.Vector.Conn()
	if _, err := con.Exec(nerCacheDDL); err != nil {
		return 0, fmt.Errorf("create ner_cache: %w", err)
	}
	fingerprint, err := nerConfigFingerprint(opts.SpacyModel, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, err
	}
	shouldReturnEarly, incremental, skipIDs, err := checkCache(con, fingerprint, opts.Force)
	if err != nil {
		return 0, err
	}
	if shouldReturnEarly {
		var cnt int
		if err := con.QueryRow("SELECT COUNT(*) FROM chunk_entities").Scan(&cnt); err != nil {
			return 0, fmt.Errorf("count chunk_entities: %w", err)
		}
		return cnt, nil
	}
	labelTypes := make([]SpacyLabel, 0)
	for _, t := range AllSpacyLabels() {
		if !numericTypes[t] {
			labelTypes = append(labelTypes, t)
		}
	}
	matcher := NewSpacyMatcher(opts.SpacyModel, true, labelTypes)
	allChunks, err := store.Vector.GetAllChunks()
	if err != nil {
		return 0, fmt.Errorf("get all chunks: %w", err)
	}
	schemaMatcher, dataMatcher, err := buildVocabMatchers(allChunks, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, err
	}
	chunksToProcess := collectChunksToProcess(allChunks, skipIDs)
	entityIndex, entityMeta, err := runNEROnChunks(chunksToProcess, matcher, schemaMatcher, dataMatcher)
	if err != nil {
		return 0, err
	}
	data := entityIndex.ToDict()
	if err := persistAssociations(con, data, entityMeta, incremental); err != nil {
		return 0, err
	}
	var allChunkCount int
	if err := con.QueryRow("SELECT COUNT(*) FROM embeddings").Scan(&allChunkCount); err != nil {
		return 0, fmt.Errorf("count embeddings: %w", err)
	}
	if _, err := con.Exec(
		"INSERT OR REPLACE INTO ner_cache(config_fingerprint, chunk_count) VALUES (?, ?)",
		fingerprint, allChunkCount,
	); err != nil {
		return 0, fmt.Errorf("upsert ner_cache: %w", err)
	}
	if opts.BuildContextGraph {
		if err := buildContextGraphEdges(con, opts.Namespace, true); err != nil {
			return 0, err
		}
	}
	return len(data["associations"].([]interface{})), nil
}

// IndexChunk records entity associations for one chunk.
// Returns the list of EntityAssociation objects created for this chunk.
func (idx *EntityIndex) IndexChunk(chunkID string, chunkContent string, matches []EntityMatch) []EntityAssociation {
	idx.totalChunks++
	chunkLength := len(chunkContent)
	if chunkLength < 1 {
		chunkLength = 1
	}
	associations := make([]EntityAssociation, 0, len(matches))
	for _, match := range matches {
		firstPos := 0
		if len(match.Positions) > 0 {
			firstPos = match.Positions[0]
		}
		score := idx.computeScore(match.Frequency, firstPos, chunkLength, match.EntityID)
		assoc := EntityAssociation{
			EntityID:    match.EntityID,
			ChunkID:     chunkID,
			Frequency:   match.Frequency,
			Positions:   match.Positions,
			Score:       score,
			ChunkLength: chunkLength,
		}
		if idx.entityToChunks[match.EntityID] == nil {
			idx.entityToChunks[match.EntityID] = make(map[string]*EntityAssociation)
		}
		idx.entityToChunks[match.EntityID][chunkID] = &assoc
		if idx.chunkToEntities[chunkID] == nil {
			idx.chunkToEntities[chunkID] = make(map[string]*EntityAssociation)
		}
		idx.chunkToEntities[chunkID][match.EntityID] = &assoc
		associations = append(associations, assoc)
	}
	return associations
}

// IDScore is a (id, score) pair.
type IDScore struct {
	ID    string
	Score float64
}

// GetChunksForEntity returns (chunkID, score) pairs for an entity, ranked by score desc.
// If topN is non-nil, only that many results are returned.
func (idx *EntityIndex) GetChunksForEntity(entityID string, topN *int) []IDScore {
	assocs := idx.entityToChunks[entityID]
	ranked := make([]*EntityAssociation, 0, len(assocs))
	for _, a := range assocs {
		ranked = append(ranked, a)
	}
	sort.Slice(ranked, func(i, j int) bool {
		return ranked[i].Score > ranked[j].Score
	})
	result := make([]IDScore, 0, len(ranked))
	for _, a := range ranked {
		result = append(result, IDScore{ID: a.ChunkID, Score: a.Score})
	}
	if topN != nil && *topN < len(result) {
		return result[:*topN]
	}
	return result
}

// GetEntitiesForChunk returns (entityID, score) pairs for a chunk, ranked by score desc.
func (idx *EntityIndex) GetEntitiesForChunk(chunkID string) []IDScore {
	assocs := idx.chunkToEntities[chunkID]
	ranked := make([]*EntityAssociation, 0, len(assocs))
	for _, a := range assocs {
		ranked = append(ranked, a)
	}
	sort.Slice(ranked, func(i, j int) bool {
		return ranked[i].Score > ranked[j].Score
	})
	result := make([]IDScore, 0, len(ranked))
	for _, a := range ranked {
		result = append(result, IDScore{ID: a.EntityID, Score: a.Score})
	}
	return result
}

