// ToDict serialises the index to a plain map (JSON-compatible).
func (idx *EntityIndex) ToDict() map[string]interface{} {
	assocs := make([]map[string]interface{}, 0)
	for _, chunkMap := range idx.entityToChunks {
		for _, a := range chunkMap {
			assocs = append(assocs, map[string]interface{}{
				"entity_id":    a.EntityID,
				"chunk_id":     a.ChunkID,
				"frequency":    a.Frequency,
				"positions":    a.Positions,
				"score":        a.Score,
				"chunk_length": a.ChunkLength,
			})
		}
	}
	return map[string]interface{}{
		"total_chunks":  idx.totalChunks,
		"score_weights": []float64{idx.fw, idx.pw, idx.sw},
		"associations":  assocs,
	}
}

// LoadEntityIndexFromDB restores an EntityIndex from the chunk_entities table.
// If namespace is non-nil, only associations for that namespace are loaded.
func LoadEntityIndexFromDB(con *sql.DB, namespace *string) (*EntityIndex, error) {
	var query string
	var args []interface{}
	if namespace != nil {
		query = "SELECT chunk_id, entity_id, frequency, positions_json, score FROM chunk_entities WHERE namespace = ?"
		args = []interface{}{*namespace}
	} else {
		query = "SELECT chunk_id, entity_id, frequency, positions_json, score FROM chunk_entities"
	}
	rows, err := con.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("query chunk_entities: %w", err)
	}
	defer rows.Close()
	type rowData struct {
		chunkID, entityID, posJSON string
		frequency int
		score     float64
	}
	var collected []rowData
	for rows.Next() {
		var r rowData
		if err := rows.Scan(&r.chunkID, &r.entityID, &r.frequency, &r.posJSON, &r.score); err != nil {
			return nil, fmt.Errorf("scan chunk_entities row: %w", err)
		}
		collected = append(collected, r)
	}
	if len(collected) == 0 {
		return NewEntityIndex(0.4, 0.3, 0.3), nil
	}
	var countQuery string
	if namespace != nil {
		countQuery = "SELECT COUNT(DISTINCT chunk_id) FROM embeddings WHERE namespace = ?"
	} else {
		countQuery = "SELECT COUNT(DISTINCT chunk_id) FROM embeddings"
	}
	var totalChunks int
	if err := con.QueryRow(countQuery, args...).Scan(&totalChunks); err != nil {
		return nil, fmt.Errorf("count distinct chunks: %w", err)
	}
	idx := NewEntityIndex(0.4, 0.3, 0.3)
	idx.totalChunks = totalChunks
	for _, r := range collected {
		var positions []int
		if r.posJSON != "" {
			if err := json.Unmarshal([]byte(r.posJSON), &positions); err != nil {
				return nil, fmt.Errorf("unmarshal positions: %w", err)
			}
		}
		assoc := &EntityAssociation{
			EntityID:    r.entityID,
			ChunkID:     r.chunkID,
			Frequency:   r.frequency,
			Positions:   positions,
			Score:       r.score,
			ChunkLength: 1,
		}
		if idx.entityToChunks[r.entityID] == nil {
			idx.entityToChunks[r.entityID] = make(map[string]*EntityAssociation)
		}
		idx.entityToChunks[r.entityID][r.chunkID] = assoc
		if idx.chunkToEntities[r.chunkID] == nil {
