var boundaryChars = map[rune]struct{}{
	'(': {}, ')': {}, '[': {}, ']': {}, '{': {}, '}': {},
	'<': {}, '>': {}, '*': {}, '&': {}, '^': {}, '%': {},
	'$': {}, '#': {}, '@': {}, '!': {}, '+': {}, '=': {},
	'~': {}, '`': {}, '\'': {}, '"': {}, '\\': {}, '|': {},
	'/': {}, '?': {}, ':': {}, ';': {}, ',': {}, '.': {},
	'\u2014': {}, '\u2013': {}, '-': {},
}

// stripSpan returns the adjusted (start, end, true) after stripping boundary chars and whitespace.
// Returns (0, 0, false) if the span becomes empty after stripping.
func stripSpan(text string, start, end int) (int, int, bool) {
	runes := []rune(text)
	if start < 0 || end > len(runes) || start >= end {
		return 0, 0, false
	}
	spanRunes := runes[start:end]
	newStart := start
	for _, ch := range spanRunes {
		if _, isBound := boundaryChars[ch]; isBound || unicode.IsSpace(ch) {
			newStart++
		} else {
			break
		}
	}
	newEnd := end
	trailing := runes[newStart:end]
	for i := len(trailing) - 1; i >= 0; i-- {
		ch := trailing[i]
		if _, isBound := boundaryChars[ch]; isBound || unicode.IsSpace(ch) {
			newEnd--
		} else {
			break
		}
	}
	if newEnd <= newStart {
		return 0, 0, false
	}
	return newStart, newEnd, true
}

// MergeMatches merges vocabulary and generic entity matches.
// Vocab entries always take precedence; generic entries survive only where
// their spans do not overlap any vocab span.
func MergeMatches(vocabMatches []EntityMatch, genericMatches []EntityMatch, sourceText string, boundaryStrip bool) []EntityMatch {
	// Build flat slice of all vocab spans.
	vocabSpans := make([][2]int, 0)
	for _, m := range vocabMatches {
		for _, sp := range m.Spans {
			vocabSpans = append(vocabSpans, sp)
		}
	}
	// Filter generic matches.
	survivingGeneric := make([]EntityMatch, 0)
	for _, gm := range genericMatches {
		keptSpans := make([][2]int, 0)
		for _, span := range gm.Spans {
			if boundaryStrip && sourceText != "" {
				newStart, newEnd, ok := stripSpan(sourceText, span[0], span[1])
				if !ok {
					continue
				}
				span = [2]int{newStart, newEnd}
			}
			overlapped := false
			for _, vs := range vocabSpans {
				if overlaps(span, vs) {
					overlapped = true
					break
				}
			}
			if !overlapped {
				keptSpans = append(keptSpans, span)
			}
		}
		if len(keptSpans) > 0 {
			positions := make([]int, 0, len(keptSpans))
			for _, s := range keptSpans {
				positions = append(positions, s[0])
			}
			survivingGeneric = append(survivingGeneric, EntityMatch{
				EntityID:    gm.EntityID,
				Name:        gm.Name,
				DisplayName: gm.DisplayName,
				EntityType:  gm.EntityType,
				Frequency:   len(keptSpans),
				Positions:   positions,
				Spans:       keptSpans,
			})
		}
	}
	// Combine and dedup by entity_id.
	merged := make(map[string]*EntityMatch)
	allMatches := make([]EntityMatch, 0, len(vocabMatches)+len(survivingGeneric))
	allMatches = append(allMatches, vocabMatches...)
	allMatches = append(allMatches, survivingGeneric...)
	for _, m := range allMatches {
		if _, exists := merged[m.EntityID]; !exists {
			copy := EntityMatch{
				EntityID:    m.EntityID,
				Name:        m.Name,
				DisplayName: m.DisplayName,
				EntityType:  m.EntityType,
				Frequency:   0,
				Positions:   []int{},
				Spans:       [][2]int{},
			}
			merged[m.EntityID] = &copy
		}
		existing := merged[m.EntityID]
		existingStarts := make(map[int]struct{})
		for _, s := range existing.Spans {
			existingStarts[s[0]] = struct{}{}
		}
		newSpans := make([][2]int, 0)
		for _, s := range m.Spans {
			if _, found := existingStarts[s[0]]; !found {
				newSpans = append(newSpans, s)
			}
		}
		allSpans := append(existing.Spans, newSpans...)
		sort.Slice(allSpans, func(i, j int) bool {
			if allSpans[i][0] != allSpans[j][0] {
				return allSpans[i][0] < allSpans[j][0]
			}
			return allSpans[i][1] < allSpans[j][1]
		})
		positions := make([]int, 0, len(allSpans))
		for _, s := range allSpans {
			positions = append(positions, s[0])
		}
		existing.Frequency = len(allSpans)
		existing.Positions = positions
		existing.Spans = allSpans
	}
	result := make([]EntityMatch, 0, len(merged))
	for _, em := range merged {
		result = append(result, *em)
	}
	return result
}

