// EntityMeta holds the (name, displayName, entityType) triple for an entity.
type EntityMeta struct {
	Name        string
	DisplayName string
	EntityType  string
}

// runNEROnChunks runs NER over chunksToProcess and returns the entity index and metadata.
func runNEROnChunks(
	chunksToProcess []ChunkEntry,
	matcher Matcher,
	schemaMatcher Matcher,
	dataMatcher Matcher,
) (*EntityIndex, map[string]EntityMeta, error) {
	entityIndex := NewEntityIndex(0.4, 0.3, 0.3)
	entityMeta := make(map[string]EntityMeta)

	for _, entry := range chunksToProcess {
		chunkID := entry.ChunkID
		chunk := entry.Chunk
		if schemaMatcher != nil || dataMatcher != nil {
			vocabHits := make([]EntityMatch, 0)
			if schemaMatcher != nil {
				schemaHits, err := schemaMatcher.Match(chunk.Content)
				if err != nil {
					return nil, nil, fmt.Errorf("schema_matcher.Match: %w", err)
				}
				vocabHits = MergeMatches(schemaHits, vocabHits, chunk.Content, true)
			}
			if dataMatcher != nil {
				dataHits, err := dataMatcher.Match(chunk.Content)
				if err != nil {
					return nil, nil, fmt.Errorf("data_matcher.Match: %w", err)
				}
				vocabHits = MergeMatches(dataHits, vocabHits, chunk.Content, true)
			}
			spacyHits, err := matcher.Match(chunk.Content)
			if err != nil {
				return nil, nil, fmt.Errorf("matcher.Match: %w", err)
			}
			combined := MergeMatches(vocabHits, spacyHits, chunk.Content, true)
			for _, m := range combined {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, combined)
		} else {
			matches, err := matcher.Match(chunk.Content)
			if err != nil {
				return nil, nil, fmt.Errorf("matcher.Match: %w", err)
			}
			for _, m := range matches {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, matches)
		}
	}
	entityIndex.RecomputeScores()
	return entityIndex, entityMeta, nil
}

