// RunNER runs vocabulary NER on a chunk and indexes results.
// Convenience wrapper around matcher.Match + IndexChunk.
func (idx *EntityIndex) RunNER(chunkID string, chunkContent string, matcher VocabularyMatcher) ([]EntityAssociation, error) {
	matches, err := matcher.Match(chunkContent)
	if err != nil {
		return nil, fmt.Errorf("matcher.Match: %w", err)
	}
	return idx.IndexChunk(chunkID, chunkContent, matches), nil
}

// GetAssociation returns the association for a specific (entity, chunk) pair, or nil if not found.
func (idx *EntityIndex) GetAssociation(entityID string, chunkID string) *EntityAssociation {
	chunkMap, exists := idx.entityToChunks[entityID]
	if !exists {
		return nil
	}
	assoc, exists := chunkMap[chunkID]
	if !exists {
		return nil
	}
	return assoc
}

// ChunksContainingEntity returns the number of indexed chunks that contain entityID.
func (idx *EntityIndex) ChunksContainingEntity(entityID string) int {
	if chunkMap, exists := idx.entityToChunks[entityID]; exists {
		return len(chunkMap)
	}
	return 0
}
